DELETE FROM flashcards        WHERE module_id='c1000014-0000-0000-0000-000000000014' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000014-0000-0000-0000-000000000014' AND created_by='buildout:m20';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Geodetic surveying accounts for the curvature and gravity field of the Earth; plane surveying treats a limited area as flat.','The ellipsoid is a smooth mathematical surface; the geoid is the equipotential (gravity) surface approximating mean sea level.','A datum ties coordinates to a defined reference surface and origin; NAD 83 is the U.S. horizontal datum and NAVD 88 the vertical datum (both being replaced in the 2022 modernization).']::text[], learning_objectives=ARRAY['Distinguish plane surveying from geodetic surveying and know when Earth curvature must be accounted for.','Define and relate the three reference surfaces: ellipsoid, geoid, and topographic surface.','Explain what a geodetic datum is and identify the principal horizontal and vertical datums used in the United States.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd';
DELETE FROM lesson_blocks WHERE lesson_id='8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Horizontal control provides a consistent framework of monumented points with published NAD 83 positions that all other work ties to.','Classical methods are triangulation (angles), trilateration (distances), and traverse (angles + distances); networks often combine them.','Control is built hierarchically: higher-order points control lower-order densification, so ''work from the whole to the part.''']::text[], learning_objectives=ARRAY['Describe the purpose and hierarchical structure of a horizontal control network.','Compare triangulation, trilateration, and traverse as methods of establishing horizontal control.','Explain how modern GNSS networks have largely replaced classical observation methods while preserving the hierarchical control philosophy.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='69ba0fb0-8d53-4f11-851e-bbebdb463c9d';
DELETE FROM lesson_blocks WHERE lesson_id='69ba0fb0-8d53-4f11-851e-bbebdb463c9d';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Vertical control provides published orthometric heights (elevations) on a common datum (NAVD 88) at benchmarks.','Differential leveling is the most accurate field method; trigonometric leveling and GNSS+geoid are alternatives.','Orthometric heights follow gravity (the geoid), which is why a geoid model is needed to convert GNSS ellipsoidal heights to elevations.']::text[], learning_objectives=ARRAY['Explain the purpose of a vertical control network and the meaning of orthometric height.','Describe differential (geodetic) leveling and trigonometric leveling as methods of establishing vertical control.','Identify NAVD 88, benchmarks, and the role of GNSS-derived heights in vertical control.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='96d52571-8a69-4dfc-b47b-59359e7d7006';
DELETE FROM lesson_blocks WHERE lesson_id='96d52571-8a69-4dfc-b47b-59359e7d7006';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A reference ellipsoid is defined by its semi-major axis a and flattening f; GRS 80 underlies NAD 83.','The direct problem computes a new point from a known point, azimuth, and distance; the inverse problem computes azimuth and distance between two known points.','Grid = Ground x Combined Scale Factor, where CSF = (grid scale factor) x (elevation factor).']::text[], learning_objectives=ARRAY['Define the defining and derived parameters of a reference ellipsoid (a, b, f, e).','Distinguish the direct and inverse geodetic problems and the role of the geodesic.','Apply the combined scale factor to convert between grid and ground distances on a State Plane projection.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='4476d8e4-a0c0-4db6-bf06-87d7a5f606b8';
DELETE FROM lesson_blocks WHERE lesson_id='4476d8e4-a0c0-4db6-bf06-87d7a5f606b8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A geoid model provides the geoid height N (separation between ellipsoid and geoid) at any location.','H = h - N converts GNSS ellipsoidal height h to orthometric height H.','GEOID18 is the current U.S. hybrid model; NAPGD2022 (a gravimetric geoid) will replace it as the 2022 vertical datum.']::text[], learning_objectives=ARRAY['Explain what a geoid model is and how it is used to relate ellipsoidal and orthometric heights.','Apply the relationship H = h - N to convert GNSS heights to elevations.','Identify the GEOID18 hybrid model and the forthcoming NAPGD2022 gravimetric geoid.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b3d6d0b7-f004-4e46-a866-f6dac0100dfb';
DELETE FROM lesson_blocks WHERE lesson_id='b3d6d0b7-f004-4e46-a866-f6dac0100dfb';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['NGS maintains the NSRS, the official framework of geodetic latitude, longitude, height, scale, gravity, and orientation for the U.S.','FGCS standards classify control by order/class, traditionally expressed as a relative accuracy ratio (1:n) and now also as positional accuracy.','Relative accuracy ratio = baseline length / positional error; larger denominators mean higher accuracy.']::text[], learning_objectives=ARRAY['Identify the NGS, the NSRS, and their role in U.S. geodetic control.','Explain the FGCS/FGDC orders and classes of accuracy and how relative accuracy is expressed.','Compute and interpret a relative accuracy ratio for a control line.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6b6461d5-b98e-4c1a-8b2b-24be1885df04';
DELETE FROM lesson_blocks WHERE lesson_id='6b6461d5-b98e-4c1a-8b2b-24be1885df04';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['CORS are permanent GNSS reference stations whose data and published NSRS coordinates anchor differential positioning nationwide.','OPUS (Online Positioning User Service) processes a user''s GNSS file against CORS and returns an NSRS position by email.','OPUS-Static needs longer occupations and yields higher accuracy than OPUS-RS; OPUS-Projects supports multi-station network adjustments.']::text[], learning_objectives=ARRAY['Describe the Continuously Operating Reference Station (CORS) network and its role in the NSRS.','Explain how OPUS computes a position from a submitted GNSS data file.','Differentiate OPUS-Static, OPUS-Rapid Static, and OPUS-Projects workflows and their accuracy.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b7aff6de-674b-458a-82e7-04f87a658a96';
DELETE FROM lesson_blocks WHERE lesson_id='b7aff6de-674b-458a-82e7-04f87a658a96';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Good network design provides strong geometry, redundant observations, and ties to multiple NSRS points.','Least-squares adjustment optimally distributes redundant-observation misclosures and yields rigorous uncertainty estimates.','Run a minimally constrained adjustment first to validate observations, then a fully constrained adjustment to fit the datum.']::text[], learning_objectives=ARRAY['Apply sound design principles (geometry, redundancy, ties to NSRS) when planning a control network.','Explain the purpose of a least-squares adjustment and the difference between minimally constrained and fully constrained adjustments.','Interpret adjustment outputs such as residuals, standard deviations, and error ellipses.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7ab732c3-dbd7-4cea-8b37-6df092933dce';
DELETE FROM lesson_blocks WHERE lesson_id='7ab732c3-dbd7-4cea-8b37-6df092933dce';
  'eeee2050-0000-0000-0000-000000000001', 'Combined scale factor: ground to grid distance', 'Apply the combined scale factor to reduce a measured ground distance to a State Plane grid distance.', 'Geodetic and Control Surveying — State Plane', 'Combined scale factor', 'numeric_input', 'medium', 'A line is measured on the ground as {{ground}} ft. The State Plane grid scale factor is k = {{k:f6}} and the project elevation is h = {{h}} ft (use Earth radius R = 20,906,000 ft). What is the grid distance (ft)? Grid = Ground x CSF, where CSF = k x R/(R+h).', 'ground*k*(20906000/(20906000+h))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ground","type":"integer","min":2000,"max":12000},{"name":"k","type":"float","min":0.9998,"max":1.0001,"decimals":6},{"name":"h","type":"integer","min":200,"max":4000}]'::jsonb, '[{"name":"elevFactor","formula":"20906000/(20906000+h)"},{"name":"csf","formula":"k*(20906000/(20906000+h))"}]'::jsonb, '[{"step_number":1,"title":"Elevation factor","formula":"R/(R+h)","calculation_template":"20,906,000 / (20,906,000 + {{h}}) = {{elevFactor:f6}}"},{"step_number":2,"title":"Combined scale factor","formula":"k x elevation factor","calculation_template":"{{k:f6}} x {{elevFactor:f6}} = {{csf:f6}}"},{"step_number":3,"title":"Grid distance","result_template":"{{ground}} x {{csf:f6}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The combined scale factor CSF = k x R/(R+h) = {{k:f6}} x {{elevFactor:f6}} = {{csf:f6}}. Grid = Ground x CSF = {{ground}} x {{csf:f6}} = {{_answer}} ft.', 'c1000014-0000-0000-0000-000000000014', ARRAY['buildout','module-20','practice']::text[], true, 'buildout:m20');
  'eeee2050-0000-0000-0000-000000000002', 'Relative accuracy ratio of a control baseline', 'Compute the relative accuracy ratio of a control line from its length and relative positional error.', 'Geodetic and Control Surveying — Standards', 'Relative accuracy', 'numeric_input', 'easy', 'Two control points are {{baseline}} ft apart, and the network adjustment reports a relative positional error of {{error:f3}} ft between them. What is the relative accuracy expressed as the denominator n in the ratio 1:n? (n = baseline / error)', 'baseline/error', '{"decimals":0,"unit":"(1:n)","tolerance":50}', '[{"name":"baseline","type":"integer","min":3000,"max":15000},{"name":"error","type":"float","min":0.03,"max":0.3,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Form the ratio","formula":"n = baseline / error","calculation_template":"{{baseline}} / {{error:f3}}"},{"step_number":2,"title":"Relative accuracy","result_template":"n = {{_answer}}, i.e. 1:{{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'Relative accuracy = baseline / positional error = {{baseline}} / {{error:f3}} = {{_answer}}, reported as 1:{{_answer}}.', 'c1000014-0000-0000-0000-000000000014', ARRAY['buildout','module-20','practice']::text[], true, 'buildout:m20');
  'eeee2050-0000-0000-0000-000000000003', 'Ellipsoidal to orthometric height conversion', 'Convert a GNSS ellipsoidal height to an orthometric height using a geoid model value N.', 'Geodetic and Control Surveying — Heights', 'Geoid separation', 'numeric_input', 'easy', 'A GNSS observation gives an ellipsoidal height h = {{h:f3}} m. The geoid model reports a geoid height N = {{N:f3}} m at this location. What is the orthometric height H (m)? (H = h - N)', 'h-N', '{"decimals":3,"unit":"m","tolerance":0.005}', '[{"name":"h","type":"float","min":100,"max":1500,"decimals":3},{"name":"N","type":"float","min":-53,"max":-8,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply the height relationship","formula":"H = h - N","calculation_template":"{{h:f3}} - ({{N:f3}})"},{"step_number":2,"title":"Orthometric height","result_template":"H = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Orthometric height H = h - N = {{h:f3}} - ({{N:f3}}) = {{_answer}} m. Because N is negative across the CONUS, subtracting it increases H.', 'c1000014-0000-0000-0000-000000000014', ARRAY['buildout','module-20','practice']::text[], true, 'buildout:m20');
COMMIT;
SELECT 'm20 Geodetic and Control Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000014-0000-0000-0000-000000000014') || ' blocks.' AS status;