INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000000', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'text', '{"html":"<h3>Plane versus geodetic surveying</h3><p><strong>Plane surveying</strong> treats the Earth''s surface as a flat plane, ignoring curvature. This is acceptable over small areas because the discrepancy between a level (curved) line and a true horizontal plane is tiny at short distances: only about <strong>0.0008 ft over 100 ft</strong> and roughly <strong>0.7 ft over 1 mile</strong>. <strong>Geodetic surveying</strong>, by contrast, accounts for the true size, shape, and gravity field of the Earth. It is required for large extents, for national control networks, and any time the surveyor must connect to a published geodetic framework. A typical Texas boundary survey is computed on the State Plane grid, which is itself a geodetic product even though field calculations look \"plane.\" As survey extent grows, the curvature correction and the difference between the geoid and the ellipsoid become impossible to ignore. Understanding which model applies is the first decision in any high-accuracy control project.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000001', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'text', '{"html":"<h3>Three reference surfaces</h3><p>Geodesy works with three distinct surfaces, and confusing them is the most common student error:</p><ul><li><strong>Topographic surface</strong> — the actual, irregular land surface on which we set our instruments and monuments.</li><li><strong>Geoid</strong> — an <em>equipotential</em> surface of the Earth''s gravity field that best approximates global mean sea level. Because it follows gravity, it is bumpy and undulating, dipping and rising with mass anomalies. Orthometric heights (elevations) are measured from the geoid.</li><li><strong>Ellipsoid</strong> — a smooth mathematical surface (an ellipse rotated about the minor axis) chosen to fit the geoid. It has no physical reality but is easy to compute on. Ellipsoidal (geodetic) heights from GNSS are measured from this surface.</li></ul><p>The separation between geoid and ellipsoid at a point is the <strong>geoid height N</strong>. Across the continental U.S., N ranges roughly from -8 m to -53 m. The relationship among the three heights is the foundation of the entire module and is revisited in the geoid lesson.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000002', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'equation', '{"latex":"H = h - N","label":"Orthometric height H from ellipsoidal height h and geoid height N","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000003', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'text', '{"html":"<h3>What is a datum?</h3><p>A <strong>geodetic datum</strong> is a reference system that defines the size and shape of the Earth model plus the position and orientation of that model relative to the Earth, so that coordinates have a fixed, repeatable meaning. A <strong>horizontal datum</strong> defines latitude and longitude (and the underlying ellipsoid); a <strong>vertical datum</strong> defines the zero surface for heights. In the United States the modern horizontal datum is <strong>NAD 83</strong> (North American Datum of 1983, originally referenced to the GRS 80 ellipsoid), and the vertical datum is <strong>NAVD 88</strong> (North American Vertical Datum of 1988). The global datum used by GPS is <strong>WGS 84</strong>, and the international scientific datum is <strong>ITRF</strong>. NAD 83 and WGS 84 differ by 1-2 m because NAD 83 is tied to the stable North American plate. A coordinate without a stated datum and epoch is ambiguous.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000004', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'table', '{"headers":["Surface / datum","Type","Defines","Notes"],"rows":[["Topographic surface","Physical","Actual ground","Where we survey"],["Geoid","Equipotential (gravity)","Mean sea level / orthometric height datum","Bumpy; defines elevations"],["Ellipsoid (GRS 80)","Mathematical","Latitude, longitude, ellipsoid height","Smooth; basis of NAD 83"],["NAD 83","Horizontal datum","Geodetic positions in North America","Being replaced by NATRF2022"],["NAVD 88","Vertical datum","Orthometric heights (U.S.)","Being replaced by NAPGD2022"],["WGS 84 / ITRF","Global datums","GPS / scientific positions","Earth-centered, plate-independent"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000005', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The three geodetic reference surfaces and the relationship H = h - N."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000006', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'callout', '{"type":"info","text":"Texas practice: Boundary surveys in Texas are routinely computed on the Texas State Plane Coordinate System (TSPCS), a grid projection of NAD 83. Even when the field math looks like plane surveying, the underlying coordinates are geodetic, so the surveyor must respect datum, epoch, and the ground-to-grid scale factor."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0001-0000-0000-000000000007', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'key_takeaways', '{"title":"Key Takeaways","items":["Plane surveying ignores curvature (fine over small areas, ~0.7 ft/mile error); geodetic surveying accounts for Earth''s shape and gravity.","Topographic surface = ground; geoid = gravity/mean-sea-level surface; ellipsoid = smooth math surface.","Geoid height N separates geoid and ellipsoid; H = h - N.","A datum fixes coordinates to a reference surface, origin, and epoch; U.S. uses NAD 83 (horizontal) and NAVD 88 (vertical), both being modernized in 2022."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000000', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'text', '{"html":"<h3>Purpose of horizontal control</h3><p>A <strong>horizontal control network</strong> is a framework of permanently monumented points whose horizontal positions (latitude/longitude or State Plane coordinates) are known to a stated accuracy on a common datum. It exists so that independent surveys, performed at different times by different people, all fit together without gaps or overlaps. The governing surveying maxim is <strong>\"work from the whole to the part\"</strong>: establish a few highly accurate points first, then densify with lower-order points that are constrained to them. This hierarchy prevents small local errors from accumulating into large regional distortions. In the United States these published points form the National Spatial Reference System (NSRS), maintained by the National Geodetic Survey (NGS). Every cadastral, construction, mapping, and GIS project that ties to NSRS benefits from this shared, error-controlled framework.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000001', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'text', '{"html":"<h3>Triangulation</h3><p><strong>Triangulation</strong> was the historical backbone of national networks. The surveyor measures the <em>angles</em> of a connected chain or net of triangles and measures the length of at least one precisely determined <strong>baseline</strong>; all other side lengths are then computed by the law of sines. Triangulation requires intervisible stations on hilltops and towers, and it propagates scale from the measured baseline. Its strength is in angle measurement (very precise with a theodolite); its weakness is that scale and orientation must be carried carefully and checked with additional baselines and astronomic (Laplace) azimuths. Networks were classified into orders and classes by the resulting relative accuracy.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000002', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'equation', '{"latex":"\\frac{a}{\\sin A} = \\frac{b}{\\sin B} = \\frac{c}{\\sin C}","label":"Law of sines used to propagate side lengths in triangulation","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000003', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'text', '{"html":"<h3>Trilateration and traverse</h3><p>When precise <strong>electronic distance measurement (EDM)</strong> became available, <strong>trilateration</strong> — measuring the <em>distances</em> (sides) of the triangles rather than the angles — became practical, with angles computed from the lengths. <strong>Traverse</strong> is a sequence of connected lines where both the angle at each station and the length of each course are measured; a traverse can be open, closed-loop, or connecting (tied to two known control points at each end). Modern high-order networks frequently combine all three observation types in one rigorous least-squares adjustment. In practice today, classical observations are reserved for special cases, and the bulk of horizontal control is established by <strong>GNSS (GPS) vector observations</strong>, which directly yield three-dimensional baseline vectors between stations.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000004', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'table', '{"headers":["Method","What is measured","What is computed","Key requirement"],"rows":[["Triangulation","Angles + ≥1 baseline","Side lengths (law of sines)","Intervisible stations"],["Trilateration","Distances (sides)","Angles","Precise EDM"],["Traverse","Angles and distances","Coordinates of each station","Closure check on known points"],["GNSS network","3-D baseline vectors","Adjusted 3-D positions","Sky visibility, ≥2 receivers"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000005', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'callout', '{"type":"success","text":"Today most horizontal control is established with GNSS, but the hierarchical philosophy is unchanged: tie new work to higher-order published NSRS marks, then densify."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0002-0000-0000-000000000006', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'key_takeaways', '{"title":"Key Takeaways","items":["Horizontal control is a monumented, datum-referenced framework that lets independent surveys fit together.","Triangulation measures angles + a baseline; trilateration measures distances; traverse measures both.","Build from the whole to the part: high-order points control lower-order densification.","GNSS vectors now provide the majority of horizontal control, adjusted by least squares."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000000', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'text', '{"html":"<h3>Purpose and the meaning of height</h3><p>A <strong>vertical control network</strong> is a system of monumented <strong>benchmarks</strong> whose <strong>orthometric heights</strong> (elevations) are published on a common vertical datum. In the U.S. that datum is the <strong>North American Vertical Datum of 1988 (NAVD 88)</strong>. Orthometric height is the distance from the geoid to the point, measured along the curved plumb line — it is the \"elevation\" used for drainage, flood mapping, and design, because water flows according to gravity, not according to the ellipsoid. Because the geoid is an equipotential surface, two points with the same orthometric height are on the same gravity potential: water will not flow between them. This physical meaning is exactly why vertical control cannot be obtained from geometry alone; it requires either leveling (which inherently follows gravity) or GNSS heights corrected by a geoid model.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000001', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'text', '{"html":"<h3>Differential (geodetic) leveling</h3><p><strong>Differential leveling</strong> determines the elevation difference between points by reading a graduated rod against a horizontal line of sight from a level. A backsight (BS) is read on a point of known elevation and a foresight (FS) on the new point; the difference of the sums gives the height change. For geodetic-quality leveling, NGS specifies short, balanced sight lengths, precise (often invar) rods, calibrated instruments, and double-run lines. The misclosure of a leveling line is compared against an allowable tolerance proportional to the square root of the distance run, e.g. for first-order class II the allowable misclosure is on the order of <strong>6 mm times the square root of the line length in kilometers</strong>. Differential leveling remains the most accurate practical method for vertical control over moderate distances.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000002', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'equation', '{"latex":"H_B = H_A + \\sum BS - \\sum FS","label":"Elevation of B by differential leveling","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000003', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'text', '{"html":"<h3>Trigonometric leveling and GNSS heights</h3><p><strong>Trigonometric leveling</strong> derives a height difference from a measured slope distance and vertical (zenith) angle, correcting for instrument and target heights and, over long sights, for Earth curvature and atmospheric refraction. It is faster than differential leveling and well suited to steep or inaccessible terrain, though generally less precise. Increasingly, vertical control is derived from <strong>GNSS</strong>: a receiver yields ellipsoidal height <em>h</em>, and a <strong>geoid model</strong> supplies the geoid height <em>N</em>, so the orthometric height is <em>H = h - N</em>. This GNSS-plus-geoid approach is the centerpiece of the 2022 datum modernization, which replaces the labor-intensive leveling network with a gravimetric geoid (NAPGD2022) so that elevations can be obtained directly from GNSS almost anywhere.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000004', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'table', '{"headers":["Method","Principle","Relative accuracy","Best use"],"rows":[["Differential leveling","Horizontal line of sight, rod readings","Highest (mm-level over km)","High-order vertical control"],["Trigonometric leveling","Slope distance + zenith angle","Moderate","Steep / inaccessible terrain"],["GNSS + geoid model","H = h - N","cm-level","Wide-area, modern workflows"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000005', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'callout', '{"type":"warning","text":"Do not mix height types. GNSS gives ellipsoidal height (h); benchmarks and plans use orthometric height (H). Converting between them requires a geoid model value N; ignoring N can introduce tens of meters of error."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0003-0000-0000-000000000006', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'key_takeaways', '{"title":"Key Takeaways","items":["Vertical control publishes orthometric heights (NAVD 88) at benchmarks; these follow gravity (the geoid).","Differential leveling is most accurate; misclosure tolerance scales with the square root of distance run.","Trigonometric leveling trades precision for speed over rough terrain.","GNSS + geoid model (H = h - N) is the modern approach and the basis of the 2022 vertical datum."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000000', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'text', '{"html":"<h3>Ellipsoid parameters</h3><p>The reference ellipsoid is fully described by two defining parameters and several derived ones. The <strong>semi-major axis a</strong> is the equatorial radius; the <strong>semi-minor axis b</strong> is the polar radius. The <strong>flattening f = (a - b) / a</strong> expresses how much the ellipsoid is squashed at the poles. The <strong>first eccentricity e</strong> relates to flattening by e&sup2; = 2f - f&sup2;. For the <strong>GRS 80</strong> ellipsoid that underlies NAD 83, a = 6,378,137.000 m and 1/f = 298.257222101, giving b ≈ 6,356,752.314 m. Because the Earth is only slightly flattened (f ≈ 1/298), the ellipsoid is very nearly a sphere — but that small flattening matters enormously over geodetic distances, which is why we compute on the ellipsoid rather than a sphere for the highest accuracy.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000001', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'equation', '{"latex":"f = \\frac{a-b}{a}, \\qquad e^2 = 2f - f^2","label":"Flattening and first eccentricity of an ellipsoid","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000002', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'text', '{"html":"<h3>The direct and inverse problems</h3><p>Two classic computations dominate geodetic position work. The <strong>direct (forward) problem</strong>: given the latitude/longitude of point 1, a forward azimuth, and a distance, compute the latitude/longitude of point 2 and the back azimuth. The <strong>inverse problem</strong>: given two points, compute the geodesic distance between them and the forward and back azimuths. On the ellipsoid the shortest line between two points is a <strong>geodesic</strong> (not a straight chord and not generally a great circle), and rigorous solutions (e.g., Vincenty''s formulae) iterate to millimeter precision. In day-to-day plane-coordinate work these reduce to ordinary coordinate geometry on the State Plane grid, but the surveyor must remember those grid coordinates came from an ellipsoidal computation and carry a scale distortion that must be removed to recover true ground distances.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000003', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'text', '{"html":"<h3>Grid, ground, and the combined scale factor</h3><p>A State Plane projection maps the curved ellipsoid onto a flat grid, introducing two distortions. The <strong>grid scale factor (k)</strong> accounts for the projection (how the map plane cuts the ellipsoid). The <strong>elevation factor (sometimes called the height or sea-level factor)</strong> accounts for reducing a ground distance at elevation down to the ellipsoid. Their product is the <strong>combined scale factor (CSF)</strong>. To convert a measured ground distance to grid, multiply by CSF; to go from grid to ground, divide:</p><ul><li><strong>Grid distance = Ground distance &times; CSF</strong></li><li><strong>Ground distance = Grid distance &divide; CSF</strong></li></ul><p>The elevation factor is R / (R + h), where R is the mean radius of the Earth (~20,906,000 ft) and h is the ground elevation (plus geoid height). Ignoring CSF on a Texas State Plane project can introduce distance errors of well over 1 ft per 10,000 ft at higher elevations.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000004', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'equation', '{"latex":"CSF = k \\times \\frac{R}{R + h}, \\qquad D_{grid} = D_{ground} \\times CSF","label":"Combined scale factor and grid distance","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000005', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'table', '{"headers":["Quantity","Symbol / value","Role"],"rows":[["Semi-major axis (GRS 80)","a = 6,378,137.000 m","Equatorial radius"],["Inverse flattening (GRS 80)","1/f = 298.257222101","Defines ellipsoid shape"],["Grid scale factor","k","Projection distortion"],["Elevation factor","R / (R + h)","Ground-to-ellipsoid reduction"],["Combined scale factor","CSF = k x R/(R+h)","Ground <-> grid conversion"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000006', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'callout', '{"type":"warning","text":"Texas differs in scale: West Texas project elevations (e.g., El Paso near 3,700 ft) make the elevation factor noticeably less than 1, so the combined scale factor materially shrinks ground distances when reduced to grid. Always state whether a distance is grid or ground on a TSPCS deliverable."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0004-0000-0000-000000000007', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'key_takeaways', '{"title":"Key Takeaways","items":["An ellipsoid is defined by a and f; GRS 80 (a = 6,378,137 m, 1/f = 298.257222101) underlies NAD 83.","Direct problem: known point + azimuth + distance -> new point. Inverse problem: two points -> distance + azimuths.","Grid = Ground x CSF, with CSF = grid scale factor x elevation factor.","Elevation factor = R/(R+h); high elevations make CSF significantly less than 1."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000000', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'text', '{"html":"<h3>Why a geoid model is needed</h3><p>GNSS measures position relative to the ellipsoid, returning an <strong>ellipsoidal (geodetic) height h</strong>. Engineering, drainage, and flood work need <strong>orthometric height H</strong> (elevation above the geoid). The two differ by the <strong>geoid height N</strong>, the undulating separation between the smooth ellipsoid and the gravity-defined geoid. A <strong>geoid model</strong> is a gridded surface that supplies N at any latitude/longitude, allowing the surveyor to convert between the two height systems. Without it, a GNSS observation cannot yield a usable elevation: across the contiguous U.S., N varies from about -8 m to -53 m, so the error of ignoring it is enormous. The geoid model is therefore the bridge that makes GNSS leveling possible and is the reason a modern surveyor can obtain NAVD 88-style elevations almost anywhere with a GNSS receiver.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000001', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'equation', '{"latex":"H = h - N","label":"Orthometric height from ellipsoidal height and geoid height","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000002', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'text', '{"html":"<h3>Hybrid versus gravimetric geoids</h3><p>NGS distributes two kinds of geoid models. A <strong>gravimetric geoid</strong> (e.g., the USGG series) is computed purely from gravity data and satellite gravity missions; it is the \"true\" geoid but is not tied to existing benchmark elevations. A <strong>hybrid geoid</strong> (e.g., <strong>GEOID18</strong>, the current U.S. model) starts from the gravimetric geoid and then warps it to fit the published GPS-on-benchmark control, so that GNSS-derived H values agree closely with NAVD 88 benchmark elevations. Hybrid models are practical because they make GNSS results consistent with the legacy leveling network, but they inherit the distortions and regional tilts of that network. The 2022 modernization deliberately moves away from this compromise.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000003', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'text', '{"html":"<h3>Toward NAPGD2022</h3><p>The new vertical datum, the <strong>North American-Pacific Geopotential Datum of 2022 (NAPGD2022)</strong>, will be defined primarily by a new, high-resolution <strong>gravimetric geoid model</strong> built from the airborne <strong>GRAV-D</strong> gravity survey and satellite data, rather than by physical leveling. This means orthometric heights will be obtained directly as H = h - N from GNSS plus the official geoid, with consistent accuracy nationwide and easy updates as the geoid model is refined. The change ends decades of reliance on the labor-intensive, slowly distorting passive leveling network. Surveyors will need to re-derive elevations on the new datum, and published differences between NAVD 88 and NAPGD2022 may reach a meter or more in some regions, so legacy elevations cannot be assumed equivalent.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000004', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'table', '{"headers":["Model type","Built from","Tied to benchmarks?","Example"],"rows":[["Gravimetric geoid","Gravity data (terrestrial, airborne GRAV-D, satellite)","No","USGG / NAPGD2022 geoid"],["Hybrid geoid","Gravimetric geoid warped to GPS-on-benchmark control","Yes","GEOID18 (current U.S.)"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000005', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Geoid height N varies smoothly across the CONUS (roughly -8 m to -53 m); a geoid model supplies N for the H = h - N conversion."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000006', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'callout', '{"type":"info","text":"Rule of thumb: a GNSS receiver gives h; the geoid model gives N; the elevation you put on the plan is H = h - N. Always record which geoid model version was used, because changing models changes your elevations."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0005-0000-0000-000000000007', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'key_takeaways', '{"title":"Key Takeaways","items":["A geoid model supplies the geoid height N at any location, bridging ellipsoidal and orthometric heights.","H = h - N converts GNSS ellipsoidal height to an elevation.","GEOID18 is a hybrid model fit to NAVD 88 benchmarks; gravimetric models come from gravity data.","NAPGD2022 will define elevations by a gravimetric geoid (GRAV-D), ending reliance on passive leveling."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000000', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'text', '{"html":"<h3>NGS and the NSRS</h3><p>The <strong>National Geodetic Survey (NGS)</strong>, a part of NOAA, is the federal agency responsible for defining and maintaining the <strong>National Spatial Reference System (NSRS)</strong> — the consistent national coordinate system that specifies latitude, longitude, height, scale, gravity, and orientation, and how these change over time. The NSRS is realized through published control marks, the CORS network, geoid models, and the official datums. When a surveyor \"ties to the NSRS,\" their work becomes part of a single, nationally consistent framework, which is essential for mapping, flood studies, infrastructure, and any project crossing jurisdictional lines. NGS also publishes the standards and specifications that tell surveyors how accurate their observations must be to qualify for a given order of control.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000001', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'text', '{"html":"<h3>Orders and classes of accuracy</h3><p>The <strong>Federal Geodetic Control Subcommittee (FGCS)</strong> (under the FGDC) established standards classifying geodetic control by <strong>order and class</strong>. Historically, horizontal accuracy was expressed as a <strong>relative accuracy ratio</strong> such as 1:100,000 (First Order) or 1:50,000 (Second Order, Class I), meaning the positional uncertainty between two connected points is no worse than one part in that many parts of the distance between them. Vertical control orders are expressed as an allowable misclosure proportional to the square root of the leveling distance. With the advent of GPS, NGS also adopted <strong>local and network accuracy</strong> standards expressed directly in centimeters at the 95% confidence level, which suit GNSS results better than a single ratio. Both frameworks coexist on published datasheets.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000002', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'equation', '{"latex":"\\text{Relative accuracy} = \\frac{\\text{baseline length}}{\\text{positional error}} = 1 : n","label":"Relative accuracy ratio","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000003', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'table', '{"headers":["Order / class","Relative accuracy (horizontal)","Typical use"],"rows":[["First Order","1:100,000","Primary national network, crustal motion"],["Second Order, Class I","1:50,000","Densification of primary network"],["Second Order, Class II","1:20,000","Local control, precise engineering"],["Third Order, Class I","1:10,000","General control, mapping"],["Third Order, Class II","1:5,000","Lower-accuracy local densification"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000004', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'text', '{"html":"<h3>Reading the ratio</h3><p>The <strong>relative accuracy ratio</strong> is the single number most students must be able to compute. If two control points are 12,000 ft apart and the adjustment shows a relative positional error of 0.10 ft between them, the relative accuracy is 12,000 / 0.10 = <strong>1:120,000</strong>, which would meet First Order. Note the direction of the relationship: for a fixed error, a longer baseline yields a larger (better) ratio, and for a fixed baseline, a smaller error yields a larger (better) ratio. Because the ratio mixes error and length, NGS increasingly prefers reporting positional accuracy in absolute terms (e.g., 2 cm network accuracy), but the classic ratio remains in widespread use in specifications and on legacy datasheets.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000005', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'callout', '{"type":"info","text":"Texas practice: TSPS Manual of Practice tiers Texas boundary surveys into categories (e.g., Category 1A is the highest-standard land-title survey). These TSPS categories are administered under TBPELS rules and are distinct from, but complementary to, the federal FGCS orders of geodetic control."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0006-0000-0000-000000000006', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'key_takeaways', '{"title":"Key Takeaways","items":["NGS (NOAA) defines and maintains the NSRS — the national framework of position, height, scale, gravity, and orientation.","FGCS orders/classes classify control; horizontal accuracy was traditionally a ratio (e.g., 1:100,000 First Order).","Relative accuracy = baseline / positional error; bigger denominator = higher accuracy.","Modern GNSS results are also reported as absolute local/network accuracy in cm at 95% confidence."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000000', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'text', '{"html":"<h3>The CORS network</h3><p>The <strong>Continuously Operating Reference Station (CORS)</strong> network is a system of permanently installed GNSS receivers that record satellite observations 24 hours a day and make the data publicly available. Each CORS has a precisely determined position in the NSRS and a known velocity (to account for crustal motion). Because their coordinates are published and their data are continuous, CORS act as ready-made, no-cost base stations: a surveyor can occupy a single point in the field, then differentially process against nearby CORS to obtain an NSRS position without setting up their own base. The network is operated cooperatively by NGS and hundreds of partner agencies, and its density largely determines the accuracy achievable from short observations in a given region.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000001', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'text', '{"html":"<h3>OPUS workflow</h3><p>The <strong>Online Positioning User Service (OPUS)</strong> is a free NGS web service that turns a single dual-frequency GNSS data file into an NSRS position. The user uploads a RINEX/observation file, specifies the antenna type and height, and OPUS automatically selects suitable nearby CORS, processes the baselines, and returns by email a solution report with the point''s latitude, longitude, ellipsoidal and orthometric heights, State Plane and UTM coordinates, and quality indicators (peak-to-peak errors and the RMS of the solution). The surveyor never has to own or operate a base station, and the result is tied directly to the NSRS through the CORS used. The quality of the report depends on observation length, multipath, satellite geometry, and proximity to CORS.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000002', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'table', '{"headers":["Service","Typical occupation","Solution method","Best accuracy"],"rows":[["OPUS-Static (OPUS-S)","2 hours to 48 hours","Double-difference baselines to 3 CORS","Sub-centimeter to ~1-2 cm"],["OPUS-Rapid Static (OPUS-RS)","15 minutes to 2 hours","Atmospheric interpolation across multiple CORS","Several cm (CORS-density dependent)"],["OPUS-Projects","Multiple stations / sessions","Network least-squares adjustment","Project-wide consistency, cm-level"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000003', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'text', '{"html":"<h3>Choosing the right OPUS tool</h3><p>Use <strong>OPUS-Static</strong> when you need the best single-point accuracy and can occupy the point for at least two hours; it requires three suitable CORS and produces the most robust solution. Use <strong>OPUS-Rapid Static</strong> when time is limited (occupations as short as 15 minutes), accepting that accuracy depends heavily on local CORS density and that it will not run reliably in CORS-sparse areas. For establishing a project''s worth of control, <strong>OPUS-Projects</strong> lets the surveyor upload many sessions and perform a managed <strong>network least-squares adjustment</strong>, producing internally consistent coordinates for all project marks and a formal adjustment report — the modern way to densify NSRS control for a survey or construction site.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000004', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'callout', '{"type":"success","text":"Best practice: occupy at least twice (different times of day) and compare the OPUS solutions. Agreement at the centimeter level between independent occupations is strong evidence the position is reliable before you publish it."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000005', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: OPUS processes a user''s GNSS file against surrounding CORS to return an NSRS position."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0007-0000-0000-000000000006', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'key_takeaways', '{"title":"Key Takeaways","items":["CORS are permanent, continuously recording GNSS stations with published NSRS coordinates and velocities.","OPUS processes a user''s GNSS file against CORS and emails back an NSRS position and quality report.","OPUS-Static (longer occupations) is most accurate; OPUS-RS is faster but CORS-density dependent.","OPUS-Projects performs a network least-squares adjustment for project-wide control."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000000', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'text', '{"html":"<h3>Designing the network</h3><p>A control network must be planned before it is observed. Good <strong>design</strong> rests on three pillars. First, <strong>geometry</strong>: stations should form well-conditioned figures (avoid long, thin triangles and weak intersections) so that errors are controlled in every direction. Second, <strong>redundancy</strong>: observe more than the minimum number of measurements so that blunders can be detected and the solution can be checked — redundancy is what makes a rigorous adjustment and a meaningful accuracy estimate possible. Third, <strong>connectivity to the NSRS</strong>: tie the network to at least two (preferably three or more) published horizontal control points and, for heights, to known benchmarks, so the project inherits the national datum and orientation. Thoughtful design at this stage is far cheaper than discovering weak geometry after the field work is done.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000001', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'text', '{"html":"<h3>Least-squares adjustment</h3><p>Real networks are over-determined: there are more observations than strictly needed, so they will not be perfectly consistent. A <strong>least-squares adjustment</strong> finds the single set of coordinates that minimizes the sum of the squares of the weighted observation <strong>residuals</strong> (the corrections applied to each measurement). It is the statistically optimal way to distribute misclosure, it can rigorously combine heterogeneous observations (angles, distances, GNSS vectors, level differences) by weighting each according to its expected precision, and — crucially — it produces formal uncertainty estimates for every adjusted point. Unlike ad-hoc methods such as the compass rule, least squares uses all the redundancy and gives defensible, repeatable results, which is why it is the standard for geodetic and modern GNSS networks.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000002', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'equation', '{"latex":"\\min \\sum_{i} w_i v_i^2","label":"Least-squares criterion: minimize the sum of weighted squared residuals","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000003', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'text', '{"html":"<h3>Minimally vs fully constrained; reading the output</h3><p>Adjustments are run in two stages. A <strong>minimally constrained</strong> adjustment holds just enough of the datum fixed (e.g., one position and one azimuth) so the network can float; its residuals reveal the <em>internal</em> quality of the observations and expose blunders without being contaminated by datum distortion. Once the observations pass, a <strong>fully (or over-) constrained</strong> adjustment holds all the published NSRS control fixed, fitting the network to the datum and revealing any inconsistency between your work and the existing control. Key outputs to interpret include the <strong>residuals</strong> (large ones flag problems), the <strong>standard deviations</strong> of adjusted coordinates, the <strong>error ellipses</strong> (showing the magnitude and orientation of positional uncertainty), and the <strong>reference variance / standard error of unit weight</strong>, which should be near 1.0 if the observation weights were realistic.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000004', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'table', '{"headers":["Adjustment output","What it tells you"],"rows":[["Residual (v)","Correction to a single observation; large values flag blunders"],["Standard deviation of coordinate","Precision of an adjusted point"],["Error ellipse","Magnitude and direction of a point''s positional uncertainty"],["Reference variance (unit weight)","Whether observation weights were realistic (should be ~1.0)"],["Constraint type","Minimally = check observations; fully = fit the datum"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000005', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'callout', '{"type":"warning","text":"Order matters: always validate with a minimally constrained adjustment before applying full datum constraints. Jumping straight to a fully constrained run can hide observation blunders inside forced fits to the published control."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000006', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A well-designed control network with redundant observations and adjusted error ellipses."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2010-0008-0000-0000-000000000007', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'key_takeaways', '{"title":"Key Takeaways","items":["Design for strong geometry, redundancy, and ties to multiple NSRS control points and benchmarks.","Least squares minimizes the weighted sum of squared residuals, optimally combining all observations and yielding uncertainty estimates.","Run minimally constrained first (check observations), then fully constrained (fit the datum).","Interpret residuals, standard deviations, error ellipses, and the reference variance (~1.0 = realistic weights)."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000001', 'Geoid', 'An equipotential surface of the Earth''s gravity field that best approximates global mean sea level; the reference surface for orthometric heights (elevations).', 'Bumpy, follows gravity', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000002', 'Ellipsoid', 'A smooth mathematical surface formed by rotating an ellipse about its minor axis, chosen to fit the geoid; the reference surface for geodetic latitude, longitude, and ellipsoidal height.', 'GRS 80 underlies NAD 83', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000003', 'Geodetic datum', 'A reference system defining the Earth model''s size/shape plus its position and orientation, so coordinates have a fixed, repeatable meaning. Horizontal datums define lat/long; vertical datums define heights.', 'NAD 83 / NAVD 88', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000004', 'Geoid height (N)', 'The separation between the geoid and the ellipsoid at a point, used to convert ellipsoidal height to orthometric height: H = h - N.', 'Negative across the CONUS', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000005', 'Triangulation', 'A control method in which the angles of a connected network of triangles are measured along with at least one precise baseline; remaining side lengths are computed using the law of sines.', 'Angles + baseline', 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000006', 'Trilateration', 'A control method in which the distances (sides) of triangles are measured (typically by EDM) and the angles are computed from those lengths.', 'Distances, not angles', 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000007', 'Connecting traverse', 'A traverse that begins and ends on different known control points (with known azimuths), allowing a full check of both position closure and orientation.', NULL, 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000008', 'Work from the whole to the part', 'The hierarchical principle of control surveying: establish a few high-accuracy points first, then densify with lower-order points constrained to them, to prevent error accumulation.', NULL, 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000009', 'Orthometric height (H)', 'The height of a point above the geoid measured along the curved plumb line; the ''elevation'' used for engineering and hydrology. Published on NAVD 88 in the U.S.', 'Follows gravity', 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000010', 'Benchmark', 'A permanently monumented point with a published orthometric height on a vertical datum, used as a starting/checking point for leveling.', NULL, 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000011', 'Differential leveling', 'Determining elevation differences using a level and rod: H_B = H_A + sum(BS) - sum(FS), with balanced backsight and foresight distances for high accuracy.', 'BS minus FS', 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000012', 'NAVD 88', 'North American Vertical Datum of 1988, the current U.S. vertical datum for orthometric heights, scheduled for replacement by NAPGD2022.', NULL, 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000013', 'Flattening (f)', 'A measure of how much an ellipsoid departs from a sphere: f = (a - b)/a. For GRS 80, 1/f = 298.257222101.', 'About 1/298', 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000014', 'Inverse (geodetic) problem', 'Given the coordinates of two points, compute the geodesic distance between them and the forward and back azimuths.', NULL, 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000015', 'Combined scale factor (CSF)', 'The product of the grid scale factor and the elevation (sea-level) factor, used to convert between ground and grid distances: Grid = Ground x CSF.', 'k x R/(R+h)', 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000016', 'Geodesic', 'The shortest line between two points on the surface of the ellipsoid; the curve along which geodetic distance is measured (not a straight chord or great circle).', NULL, 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000017', 'Geoid model', 'A gridded surface giving the geoid height N (ellipsoid-to-geoid separation) at any latitude/longitude, used to convert between ellipsoidal and orthometric heights.', NULL, 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000018', 'GEOID18', 'The current U.S. hybrid geoid model, derived from a gravimetric geoid warped to fit GPS-on-benchmark control so GNSS heights agree with NAVD 88.', 'Hybrid model', 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000019', 'GRAV-D', 'Gravity for the Redefinition of the American Vertical Datum: NGS''s airborne gravity campaign supplying data for the NAPGD2022 gravimetric geoid.', NULL, 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000020', 'NAPGD2022', 'North American-Pacific Geopotential Datum of 2022, the new vertical datum defined chiefly by a gravimetric geoid, replacing NAVD 88.', NULL, 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000021', 'National Geodetic Survey (NGS)', 'The NOAA agency that defines, maintains, and provides access to the National Spatial Reference System, including datums, geoid models, CORS, and OPUS.', 'Maintains the NSRS', 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000022', 'National Spatial Reference System (NSRS)', 'The consistent national coordinate system specifying latitude, longitude, height, scale, gravity, orientation, and their changes over time for the United States.', NULL, 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000023', 'Relative accuracy ratio', 'An expression of control quality as 1:n, equal to the baseline length divided by the relative positional error between two points; a larger n indicates higher accuracy.', 'Length / error', 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000024', 'FGCS', 'Federal Geodetic Control Subcommittee, which established the orders and classes of accuracy and the standards/specifications for U.S. geodetic control surveys.', NULL, 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000025', 'CORS', 'Continuously Operating Reference Station: a permanent GNSS receiver with published NSRS coordinates and velocity whose freely available data serve as a base for differential positioning.', 'Permanent GNSS base', 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000026', 'OPUS', 'Online Positioning User Service: a free NGS web tool that processes a submitted GNSS data file against CORS and returns an NSRS position by email.', NULL, 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000027', 'OPUS-Static vs OPUS-RS', 'OPUS-S uses longer occupations (2+ hours) and three CORS for the highest accuracy; OPUS-RS works with short occupations (15 min-2 hr) but its accuracy depends on local CORS density.', 'Time vs accuracy', 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000028', 'OPUS-Projects', 'An OPUS workflow that ingests multiple GNSS sessions and performs a managed network least-squares adjustment to produce consistent coordinates for many project control marks.', NULL, 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000029', 'Least-squares adjustment', 'A rigorous method that finds adjusted coordinates minimizing the sum of weighted squared observation residuals, optimally distributing redundant-observation misclosure and producing formal uncertainty estimates.', 'Minimize weighted v-squared', 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000030', 'Minimally constrained adjustment', 'An adjustment that holds only enough of the datum fixed for the network to float, used to assess the internal quality of observations and detect blunders before fitting to control.', NULL, 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000031', 'Error ellipse', 'A graphical depiction at an adjusted point showing the magnitude and orientation of its positional uncertainty (semi-major/semi-minor axes from the covariance).', NULL, 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2040-0000-0000-0000-000000000032', 'Redundancy', 'Observing more measurements than the minimum required, enabling blunder detection, a rigorous adjustment, and meaningful accuracy estimates.', 'Extra observations = checks', 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', 'surveying', ARRAY['buildout','module-20']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000001', 'Which statement best distinguishes the geoid from the ellipsoid?', 'multiple_choice', '["The geoid is a smooth mathematical surface; the ellipsoid follows gravity.","The geoid is an equipotential gravity surface (bumpy); the ellipsoid is a smooth mathematical surface.","They are identical surfaces with different names.","The geoid defines latitude and longitude; the ellipsoid defines elevations."]'::jsonb, 'The geoid is an equipotential gravity surface (bumpy); the ellipsoid is a smooth mathematical surface.', 'The geoid is an equipotential surface of Earth''s gravity field approximating mean sea level and is undulating; the ellipsoid is a smooth math surface fit to it. Elevations (orthometric heights) reference the geoid; lat/long and ellipsoidal height reference the ellipsoid.', 'easy', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000002', 'Approximately how large is the error from treating a level line as a horizontal plane over a distance of one mile?', 'multiple_choice', '["About 0.0008 ft","About 0.7 ft","About 7 ft","About 70 ft"]'::jsonb, 'About 0.7 ft', 'Curvature causes roughly 0.7 ft of departure over one mile (and only about 0.0008 ft over 100 ft), which is why plane surveying is acceptable over small areas but geodetic methods are required over large extents.', 'medium', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000003', 'A coordinate is meaningful only if its datum and epoch are stated.', 'true_false', '["True","False"]'::jsonb, 'True', 'Coordinates depend on the reference surface, origin, and time (epoch). Without a stated datum and epoch a coordinate is ambiguous, especially because NAD 83 and WGS 84 differ and positions change with crustal motion.', 'easy', 'c1000014-0000-0000-0000-000000000014', '8652bc9b-f476-4bb5-8c6b-ff3115c9e1bd', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000004', 'In classical triangulation, which quantities are measured in the field?', 'multiple_choice', '["Only the distances (sides) of the triangles","The angles of the triangles plus at least one precise baseline","Only GNSS baseline vectors","Only the elevations of the stations"]'::jsonb, 'The angles of the triangles plus at least one precise baseline', 'Triangulation measures angles and at least one baseline; remaining side lengths are computed with the law of sines. Measuring the sides instead is trilateration.', 'easy', 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000005', 'What does the principle ''work from the whole to the part'' mean for control surveying?', 'multiple_choice', '["Survey the smallest parcels first, then connect them later.","Establish a few high-accuracy points first, then densify with lower-order points constrained to them.","Always use triangulation before any other method.","Adjust each measurement independently as it is taken."]'::jsonb, 'Establish a few high-accuracy points first, then densify with lower-order points constrained to them.', 'Building hierarchically (high order controlling low order) prevents local errors from accumulating into large regional distortions.', 'medium', 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000006', 'A connecting traverse begins and ends on different known control points, allowing a check of both position closure and orientation.', 'true_false', '["True","False"]'::jsonb, 'True', 'A connecting (link) traverse is tied to known points with known azimuths at both ends, so both position misclosure and angular/orientation closure can be checked.', 'easy', 'c1000014-0000-0000-0000-000000000014', '69ba0fb0-8d53-4f11-851e-bbebdb463c9d', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000007', 'Why is a geoid model required to obtain an elevation from a GNSS observation?', 'multiple_choice', '["GNSS gives orthometric height directly, so no model is needed.","GNSS gives ellipsoidal height h; the geoid model supplies N so H = h - N can be computed.","The geoid model corrects for satellite clock errors.","The geoid model converts grid distance to ground distance."]'::jsonb, 'GNSS gives ellipsoidal height h; the geoid model supplies N so H = h - N can be computed.', 'GNSS measures height above the ellipsoid (h). Elevations are orthometric (H), measured from the geoid. The geoid model provides N, and H = h - N.', 'medium', 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000008', 'Which field method generally provides the highest accuracy for vertical control over moderate distances?', 'multiple_choice', '["Trigonometric leveling","Differential (geodetic) leveling","Single-frequency GNSS autonomous positioning","Barometric leveling"]'::jsonb, 'Differential (geodetic) leveling', 'Differential leveling with balanced sights and precise rods is the most accurate practical method; trigonometric leveling trades precision for speed, and barometric/autonomous methods are far less accurate.', 'easy', 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000009', 'The allowable misclosure of a leveling line is typically proportional to the square root of the distance run.', 'true_false', '["True","False"]'::jsonb, 'True', 'Random leveling errors accumulate with the square root of the number of setups/distance, so specifications express the allowable misclosure as a constant times the square root of the line length.', 'medium', 'c1000014-0000-0000-0000-000000000014', '96d52571-8a69-4dfc-b47b-59359e7d7006', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000010', 'The defining parameters of the GRS 80 ellipsoid (used by NAD 83) are best stated as:', 'multiple_choice', '["a = 6,378,137 m and 1/f = 298.257222101","a = 6,356,752 m and 1/f = 100","a = 6,371,000 m and f = 0 (a sphere)","a = 20,906,000 ft and 1/f = 1"]'::jsonb, 'a = 6,378,137 m and 1/f = 298.257222101', 'GRS 80 is defined by the semi-major axis a = 6,378,137.000 m and inverse flattening 1/f = 298.257222101, giving b about 6,356,752 m.', 'medium', 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000011', 'To convert a measured ground distance to a grid distance on a State Plane projection, you should:', 'multiple_choice', '["Divide the ground distance by the combined scale factor.","Multiply the ground distance by the combined scale factor.","Add the geoid height N to the ground distance.","Multiply by the grid scale factor only, ignoring elevation."]'::jsonb, 'Multiply the ground distance by the combined scale factor.', 'Grid = Ground x CSF. The combined scale factor is the product of the grid scale factor and the elevation factor R/(R+h); going the other way (grid to ground) you divide.', 'medium', 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000012', 'The inverse geodetic problem computes the distance and azimuths between two points whose coordinates are already known.', 'true_false', '["True","False"]'::jsonb, 'True', 'The inverse problem takes two known points and returns the geodesic distance and the forward/back azimuths. The direct problem instead computes a new point from a known point, azimuth, and distance.', 'easy', 'c1000014-0000-0000-0000-000000000014', '4476d8e4-a0c0-4db6-bf06-87d7a5f606b8', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000013', 'GEOID18 is best described as which kind of model?', 'multiple_choice', '["A purely gravimetric geoid with no benchmark fit","A hybrid geoid: a gravimetric geoid warped to fit GPS-on-benchmark control","An ellipsoid definition","A horizontal datum"]'::jsonb, 'A hybrid geoid: a gravimetric geoid warped to fit GPS-on-benchmark control', 'GEOID18 is a hybrid model: it starts from a gravimetric geoid and is adjusted to fit published GPS-on-benchmark points so GNSS-derived heights agree with NAVD 88.', 'medium', 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000014', 'The new vertical datum NAPGD2022 will be defined primarily by which of the following?', 'multiple_choice', '["A re-run of the passive leveling network","A high-resolution gravimetric geoid model built from GRAV-D and satellite data","The WGS 84 ellipsoid","Tide-gauge readings only"]'::jsonb, 'A high-resolution gravimetric geoid model built from GRAV-D and satellite data', 'NAPGD2022 replaces leveling-based NAVD 88 with a gravimetric geoid (using airborne GRAV-D and satellite gravity data), so elevations come from GNSS via H = h - N.', 'medium', 'c1000014-0000-0000-0000-000000000014', 'b3d6d0b7-f004-4e46-a866-f6dac0100dfb', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000015', 'What does the National Geodetic Survey (NGS) maintain?', 'multiple_choice', '["Only the GPS satellite constellation","The National Spatial Reference System (NSRS)","State boundary records","The Public Land Survey System monuments"]'::jsonb, 'The National Spatial Reference System (NSRS)', 'NGS (part of NOAA) defines and maintains the NSRS: latitude, longitude, height, scale, gravity, and orientation, realized through control marks, CORS, geoid models, and the datums.', 'easy', 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000016', 'Two connected control points are 8,000 ft apart and their relative positional error is 0.08 ft. What is the relative accuracy ratio?', 'multiple_choice', '["1:1,000","1:10,000","1:100,000","1:800"]'::jsonb, '1:100,000', 'Relative accuracy = baseline / error = 8,000 / 0.08 = 100,000, i.e., 1:100,000 (First Order quality).', 'medium', 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000017', 'For a fixed positional error, a longer baseline between two control points produces a higher (better) relative accuracy ratio.', 'true_false', '["True","False"]'::jsonb, 'True', 'Because the ratio is baseline/error, increasing the baseline with the error held constant increases the denominator n, indicating higher relative accuracy.', 'medium', 'c1000014-0000-0000-0000-000000000014', '6b6461d5-b98e-4c1a-8b2b-24be1885df04', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000018', 'What is a CORS in the context of the NSRS?', 'multiple_choice', '["A one-time GNSS observation submitted to NGS","A permanently installed GNSS station with published NSRS coordinates whose data are continuously available","A geoid model file","A type of total station"]'::jsonb, 'A permanently installed GNSS station with published NSRS coordinates whose data are continuously available', 'CORS are permanent, continuously recording GNSS receivers with published NSRS positions and velocities, used as free base stations for differential positioning.', 'easy', 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000019', 'Which OPUS service is most appropriate for obtaining the highest single-point accuracy when you can occupy a point for several hours?', 'multiple_choice', '["OPUS-Rapid Static (OPUS-RS)","OPUS-Static (OPUS-S)","OPUS-Projects only","None; OPUS cannot reach centimeter accuracy"]'::jsonb, 'OPUS-Static (OPUS-S)', 'OPUS-Static uses longer occupations (2+ hours) and three CORS to produce the most robust, highest-accuracy single-point solution; OPUS-RS is faster but less accurate and CORS-density dependent.', 'medium', 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000020', 'OPUS returns a processed position to the user by email after comparing the submitted GNSS file against CORS.', 'true_false', '["True","False"]'::jsonb, 'True', 'OPUS automatically selects suitable CORS, processes the uploaded GNSS file, and emails a solution report containing the NSRS position and quality indicators.', 'easy', 'c1000014-0000-0000-0000-000000000014', 'b7aff6de-674b-458a-82e7-04f87a658a96', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000021', 'Why is a minimally constrained adjustment run before a fully constrained adjustment?', 'multiple_choice', '["To make the field work go faster","To assess the internal quality of the observations and detect blunders before fitting to the datum","Because fully constrained adjustments cannot compute residuals","To avoid needing any published control"]'::jsonb, 'To assess the internal quality of the observations and detect blunders before fitting to the datum', 'A minimally constrained adjustment lets the network float so observation residuals reveal blunders without datum distortion; the fully constrained run then fits the work to the published NSRS control.', 'hard', 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000022', 'What is the objective minimized in a least-squares adjustment?', 'multiple_choice', '["The largest single observation residual","The sum of the weighted squared residuals of the observations","The number of control points held fixed","The total length of all baselines"]'::jsonb, 'The sum of the weighted squared residuals of the observations', 'Least squares finds coordinates that minimize the sum of weighted squared residuals, optimally distributing misclosure across all redundant observations and yielding rigorous uncertainty estimates.', 'medium', 'c1000014-0000-0000-0000-000000000014', '7ab732c3-dbd7-4cea-8b37-6df092933dce', ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2030-0000-0000-0000-000000000023', 'Redundant observations in a control network are unnecessary if the surveyor is careful, because they only add cost.', 'true_false', '["True","False"]'::jsonb, 'False', 'Redundancy is essential: it allows blunder detection, makes a rigorous least-squares adjustment possible, and produces meaningful accuracy estimates. Without redundant observations there is no independent check.', 'medium', 'c1000014-0000-0000-0000-000000000014', NULL, ARRAY['buildout','module-20']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
