INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2060-0000-0000-0000-000000000001', 'A line is measured on the ground as {{ground}} ft. The State Plane grid scale factor is k = {{k:f6}} and the project elevation is h = {{h}} ft (use Earth radius R = 20,906,000 ft). What is the grid distance (ft)? Grid = Ground x CSF, where CSF = k x R/(R+h).', 'numeric_input', '[]'::jsonb, '0', 'The combined scale factor CSF = k x R/(R+h) = {{k:f6}} x {{elevFactor:f6}} = {{csf:f6}}. Grid = Ground x CSF = {{ground}} x {{csf:f6}} = {{_answer}} ft.', 'medium', 'c1000014-0000-0000-0000-000000000014', NULL, ARRAY['buildout','module-20','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2050-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2060-0000-0000-0000-000000000002', 'Two control points are {{baseline}} ft apart, and the network adjustment reports a relative positional error of {{error:f3}} ft between them. What is the relative accuracy expressed as the denominator n in the ratio 1:n? (n = baseline / error)', 'numeric_input', '[]'::jsonb, '0', 'Relative accuracy = baseline / positional error = {{baseline}} / {{error:f3}} = {{_answer}}, reported as 1:{{_answer}}.', 'easy', 'c1000014-0000-0000-0000-000000000014', NULL, ARRAY['buildout','module-20','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2050-0000-0000-0000-000000000002', 50);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2060-0000-0000-0000-000000000003', 'A GNSS observation gives an ellipsoidal height h = {{h:f3}} m. The geoid model reports a geoid height N = {{N:f3}} m at this location. What is the orthometric height H (m)? (H = h - N)', 'numeric_input', '[]'::jsonb, '0', 'Orthometric height H = h - N = {{h:f3}} - ({{N:f3}}) = {{_answer}} m. Because N is negative across the CONUS, subtracting it increases H.', 'easy', 'c1000014-0000-0000-0000-000000000014', NULL, ARRAY['buildout','module-20','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2050-0000-0000-0000-000000000003', 0.005);
